#!/usr/bin/env node
/**
 * Sonnet hook quality test — 10 real records.
 * Regenerates outreach_hook for the top 10 prospects using claude-sonnet-4-6
 * with the lean single-call pattern. Stores results in Supabase and logs
 * token usage per record for comparison.
 *
 * Before: hooks were generated by claude-haiku-4-5-20251001 via backfill_outreach_hooks.js
 * After:  hooks generated by claude-sonnet-4-6 with same lean pattern
 */

const https = require('https');
const fs = require('fs');

// ─── Config ───────────────────────────────────────────────────────────────────

const env = Object.fromEntries(
  fs.readFileSync('C:/nithdigital/.env.local', 'utf8')
    .split('\n')
    .filter(l => l.includes('='))
    .map(l => [l.split('=')[0].trim(), l.slice(l.indexOf('=') + 1).trim()])
);

const ANTHROPIC_API_KEY = env.ANTHROPIC_API_KEY;
const SUPABASE_URL = 'https://mrdozyxbonbukpmywxqi.supabase.co';
const SUPABASE_KEY = env.SUPABASE_SERVICE_ROLE_KEY;
const MODEL = 'claude-sonnet-4-6';

// ─── The 10 real records (top by score_overall) ───────────────────────────────

const RECORDS = [
  { id: 'c407d45a-2b94-44a9-abad-248f829e3f28', business_name: 'Ian Lewis Plumber', sector: 'Trades', why_them: 'Trading since 1986, hand-coded HTML site from early 2000s, no mobile responsiveness, no SSL, no contact form. Gas Safe registered. Easy close — show him mobile view of his site.', existing_hook: "Your website doesn't display properly on mobile, which is where most customers search for emergency plumber services." },
  { id: '81f42ab8-9bc8-47a4-b568-bf80f5a81235', business_name: 'Brighouse Bay Trekking', sector: 'Activity/Tourism', why_them: "Established since 1970s, TRSS-approved. Weebly site from 2009, only two low-res images, no online booking, no pricing. Sits adjacent to 5-star Brighouse Bay Holiday Park — huge captive audience.", existing_hook: "Your website hasn't been updated since 2009, and potential customers can't book treks or see current pricing anywhere online." },
  { id: 'a9594a66-fdfa-4364-9bba-03f144d8c789', business_name: 'Dark Sky Ranger', sector: 'Activity/Tourism', why_them: "UK first International Dark Sky Park operator. Wix site with no booking calendar, empty tour schedule, broken email signup. 4.9 star reviews. World-class product, terrible website.", existing_hook: "Your booking calendar isn't showing up on your Wix site, which means potential visitors can't actually reserve their stargazing tours." },
  { id: '813613f3-c7bb-44a5-a433-1b81bcd7566b', business_name: 'Ardchoille Guest House', sector: 'Accommodation', why_them: "Prime Portpatrick location overlooking harbour. Legacy site, no online booking, broken Google+ links, no mobile optimisation. 80+ TripAdvisor reviews at 4.3 stars.", existing_hook: "Your website doesn't let guests book directly online, which means you're losing bookings to competitors who do." },
  { id: '1e5bbacd-60a1-4395-bf21-03d03f838047', business_name: 'Salon31', sector: 'Beauty/Hair', why_them: "Premium salon branding but Book button links to contact form only, not booking calendar. Competitors have direct booking. Custom HTML means developer needed for any updates.", existing_hook: "Your booking button takes customers to a contact form instead of letting them book directly like your competitors do." },
  { id: '97c51f0f-e4f6-45e2-aeb9-54d09a4e5a7d', business_name: 'GM Thomson & Co Estate Agents', sector: 'Professional Services', why_them: "Since 1953, four offices across D&G. Uses ASP technology from 2001, not mobile-responsive, no advanced search, no valuation tool. Main competitor Williamson & Henry also mediocre — first mover wins.", existing_hook: "Your property listings aren't loading properly on mobile, which is where most buyers start their search in 2024." },
  { id: 'e897bbc9-0c8c-4b97-89e2-0e7ba57c4510', business_name: 'Carson & Trotter Chartered Accountants', sector: 'Professional Services', why_them: "95+ years in business. Critical SSL certificate error — cert belongs to conscious.co.uk/law-league.com. Rep-damaging for a firm built on trust. Emergency call opportunity.", existing_hook: "Your website's SSL certificate is pointing to the wrong domain, which makes browsers warn visitors away before they even see your services." },
  { id: 'bec2215a-3328-4746-8f40-9bb2c6d16a8c', business_name: 'Rennie Accountants', sector: 'Professional Services', why_them: "Since 1983. Generic WordPress theme, no team bios, no testimonials, outdated carousel. Strong content opportunity for D&G sole trader tax guides.", existing_hook: "Your website looks like it hasn't been updated since 2015, which probably isn't the impression you want when accountants visit." },
  { id: '904a0671-27ec-460f-8ae1-582625677166', business_name: 'Kinetica Physiotherapy Clinic', sector: 'Healthcare', why_them: "No website whatsoever — presence is Facebook-only despite being a well-established, highly-rated Dumfries clinic with over 23 years of experience. No online booking, no service or pricing information available digitally. An experienced multi-treatment clinic (acupuncture, joint manipulation, corticosteroid injections) is losing new patients every day to competitors with functional websites.", existing_hook: "Your clinic's only online presence is Facebook, which means patients can't book appointments or find your pricing before contacting you." },
  { id: 'e161c093-0ef9-4e27-98dd-b08b69bc3e58', business_name: 'Abbey Cottage Tearoom', sector: 'Food & Drink', why_them: "Adjacent to Sweetheart Abbey. 400+ Google reviews at 4.7 stars. No online booking — afternoon tea must be booked by phone.", existing_hook: "Your afternoon tea bookings are still stuck on phone calls when customers expect to book online." }
];

// ─── HTTP helpers ─────────────────────────────────────────────────────────────

function callAnthropic(systemPrompt, userMessage, maxTokens = 100) {
  const body = {
    model: MODEL,
    max_tokens: maxTokens,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }]
  };
  const bodyStr = JSON.stringify(body);
  const options = {
    hostname: 'api.anthropic.com',
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'x-api-key': ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
      'content-length': Buffer.byteLength(bodyStr)
    }
  };
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
        catch (e) { resolve({ status: res.statusCode, body: data }); }
      });
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

function supabasePatch(id, hook) {
  const path = `/rest/v1/prospects?id=eq.${id}`;
  const bodyStr = JSON.stringify({ outreach_hook: hook });
  const options = {
    hostname: new URL(SUPABASE_URL).hostname,
    path,
    method: 'PATCH',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
      'content-length': Buffer.byteLength(bodyStr)
    }
  };
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve({ status: res.statusCode }));
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

// ─── Lean system prompt (Sonnet) ──────────────────────────────────────────────

const SYSTEM_PROMPT = `You write cold email opening sentences for a web design agency targeting small UK businesses in Dumfries & Galloway, Scotland.

Given research notes about a prospect, write exactly ONE sentence that:
- Addresses the business owner in second person (you/your)
- Identifies one specific, observable problem with their online presence
- Sounds like something noticed while casually browsing — not a scraped data report
- Is 25 words or fewer
- Does NOT mention internal notes like "Easy close", "Upsell", star ratings, review counts, or accreditation names
- Does NOT always start with "Your" or "I noticed" — vary the opener naturally
- Focuses on the single most impactful website problem

Reply with ONLY the sentence. No quotes. No explanation. No preamble.`;

// ─── Main ─────────────────────────────────────────────────────────────────────

async function main() {
  console.log('═'.repeat(70));
  console.log('  SONNET HOOK QUALITY TEST — 10 REAL RECORDS');
  console.log(`  Model: ${MODEL}`);
  console.log('  Writing results to Supabase');
  console.log('═'.repeat(70));

  const results = [];
  let totalInputTokens = 0;
  let totalOutputTokens = 0;

  for (let i = 0; i < RECORDS.length; i++) {
    const rec = RECORDS[i];
    console.log(`\n[${i + 1}/10] ${rec.business_name}`);

    const userMsg = `Business: ${rec.business_name}
Sector: ${rec.sector}
Notes: ${rec.why_them}`;

    const res = await callAnthropic(SYSTEM_PROMPT, userMsg, 100);

    if (res.status !== 200 || !res.body.content) {
      console.error(`  ERROR ${res.status}: ${JSON.stringify(res.body).slice(0, 200)}`);
      continue;
    }

    const newHook = res.body.content[0]?.text?.trim();
    const input = res.body.usage?.input_tokens || 0;
    const output = res.body.usage?.output_tokens || 0;
    totalInputTokens += input;
    totalOutputTokens += output;

    // Store in Supabase
    const patch = await supabasePatch(rec.id, newHook);
    const stored = patch.status >= 200 && patch.status < 300;

    console.log(`  Tokens:   ${input} in / ${output} out / ${input + output} total`);
    console.log(`  BEFORE:   "${rec.existing_hook}"`);
    console.log(`  AFTER:    "${newHook}"`);
    console.log(`  Stored:   ${stored ? 'YES' : 'FAILED (' + patch.status + ')'}`);

    results.push({
      business: rec.business_name,
      sector: rec.sector,
      before: rec.existing_hook,
      after: newHook,
      tokens: input + output,
      stored
    });

    // Avoid rate limiting
    await new Promise(r => setTimeout(r, 300));
  }

  // ─── Summary ────────────────────────────────────────────────────────────────

  const totalTokens = totalInputTokens + totalOutputTokens;
  const avgTokens = Math.round(totalTokens / results.length);
  const stored = results.filter(r => r.stored).length;

  console.log('\n' + '═'.repeat(70));
  console.log('  SUMMARY');
  console.log('═'.repeat(70));
  console.log(`  Records processed:    ${results.length}/10`);
  console.log(`  Successfully stored:  ${stored}/10`);
  console.log(`  Total input tokens:   ${totalInputTokens}`);
  console.log(`  Total output tokens:  ${totalOutputTokens}`);
  console.log(`  Total tokens:         ${totalTokens}`);
  console.log(`  Average per record:   ${avgTokens} tokens`);
  console.log(`  Projected per 100:    ${avgTokens * 100} tokens`);
  console.log('═'.repeat(70));
}

main().catch(err => {
  console.error('Fatal:', err.message);
  process.exit(1);
});
